public class RabbitRuntimeHints implements RuntimeHintsRegistrar {

	@Override
	public void registerHints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		ProxyHints proxyHints = hints.proxies();
		proxyHints.registerJdkProxy(ChannelProxy.class);
		proxyHints.registerJdkProxy(ChannelProxy.class, PublisherCallbackChannel.class);
		proxyHints.registerJdkProxy(builder ->
				builder.proxiedInterfaces(TypeReference.of(
						"org.springframework.amqp.rabbit.listener.AbstractMessageListenerContainer$ContainerDelegate"))
						.proxiedInterfaces(SpringProxy.class, Advised.class, DecoratingProxy.class));
	}

}

class ConditionEvaluationReportLoggingProcessor implements BeanFactoryInitializationAotProcessor {

	@Override
	public @Nullable BeanFactoryInitializationAotContribution processAheadOfTime(
			ConfigurableListableBeanFactory beanFactory) {
		logConditionEvaluationReport(beanFactory);
		return null;
	}

	private void logConditionEvaluationReport(ConfigurableListableBeanFactory beanFactory) {
		new ConditionEvaluationReportLogger(LogLevel.DEBUG, () -> ConditionEvaluationReport.get(beanFactory))
			.logReport(false);
	}

}

class ConfigDataPropertiesRuntimeHints implements RuntimeHintsRegistrar {

	@Override
	public void registerHints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		BindableRuntimeHintsRegistrar.forTypes(ConfigDataProperties.class).registerHints(hints);
		Method method = ReflectionUtils.findMethod(ConfigDataLocation.class, "of", String.class);
		Assert.state(method != null, "'method' must not be null");
		hints.reflection().registerMethod(method, ExecutableMode.INVOKE);
	}

}

public class ConfigTreeConfigDataLoader implements ConfigDataLoader<ConfigTreeConfigDataResource> {

	@Override
	public ConfigData load(ConfigDataLoaderContext context, ConfigTreeConfigDataResource resource)
			throws IOException, ConfigDataResourceNotFoundException {
		Path path = resource.getPath();
		ConfigDataResourceNotFoundException.throwIfDoesNotExist(resource, path);
		String name = "Config tree '" + path + "'";
		ConfigTreePropertySource source = new ConfigTreePropertySource(name, path, Option.AUTO_TRIM_TRAILING_NEW_LINE);
		return new ConfigData(Collections.singletonList(source));
	}

}

class SystemEnvironmentConfigDataLoader implements ConfigDataLoader<SystemEnvironmentConfigDataResource> {

	@Override
	public ConfigData load(ConfigDataLoaderContext context, SystemEnvironmentConfigDataResource resource)
			throws IOException, ConfigDataResourceNotFoundException {
		List<PropertySource<?>> loaded = resource.load();
		if (loaded == null) {
			throw new ConfigDataResourceNotFoundException(resource);
		}
		return new ConfigData(loaded);
	}

}

class IncompatibleConfigurationFailureAnalyzer extends AbstractFailureAnalyzer<IncompatibleConfigurationException> {

	@Override
	protected FailureAnalysis analyze(Throwable rootFailure, IncompatibleConfigurationException cause) {
		String action = String.format("Review the docs for %s and change the configured values.",
				String.join(", ", cause.getIncompatibleKeys()));
		return new FailureAnalysis(cause.getMessage(), action, cause);
	}

}

class AotInitializerNotFoundFailureAnalyzer extends AbstractFailureAnalyzer<AotInitializerNotFoundException> {

	@Override
	protected FailureAnalysis analyze(Throwable rootFailure, AotInitializerNotFoundException cause) {
		return new FailureAnalysis(cause.getMessage(), "Consider the following:\n"
				+ "\tDid you build the application with enabled AOT processing?\n"
				+ "\tIs the main class %s correct?\n".formatted(cause.getMainClass().getName())
				+ "\tIf you want to run the application in regular mode, remove the system property 'spring.aot.enabled'",
				cause);
	}

}

class PatternParseFailureAnalyzer extends AbstractFailureAnalyzer<PatternParseException> {

	@Override
	protected FailureAnalysis analyze(Throwable rootFailure, PatternParseException cause) {
		return new FailureAnalysis("Invalid mapping pattern detected:\n" + cause.toDetailedString(),
				"Fix this pattern in your application or switch to the legacy parser implementation with "
						+ "'spring.mvc.pathmatch.matching-strategy=ant_path_matcher'.",
				cause);
	}

}

@SuppressWarnings("serial")
public class ListenerFailedRuleBasedTransactionAttribute extends RuleBasedTransactionAttribute {

	@Override
	public boolean rollbackOn(Throwable ex) {
		if (ex instanceof ListenerExecutionFailedException && ex.getCause() != null) {
			return super.rollbackOn(ex.getCause());
		}
		else {
			return super.rollbackOn(ex);
		}
	}

}

